import { isSafeLinkUrl } from './urlSafety';

/**
 * A single inline token inside a restricted-markdown line. Deliberately a
 * plain data structure — no `React.ReactNode` — so both the plugin WebView
 * and the www admin can render it with their own JSX without this package
 * depending on React.
 */
export type InlineToken =
  | { type: 'text'; text: string }
  | { type: 'bold'; text: string }
  | { type: 'link'; label: string; href: string };

/** A block-level unit of restricted-markdown content. */
export type RestrictedMarkdownBlock =
  | { type: 'paragraph'; tokens: InlineToken[] }
  | { type: 'list'; items: InlineToken[][] };

// Matches **bold** or [label](url) tokens; everything else is left as plain text.
// The url group tolerates one level of nested parens (e.g. `javascript:alert(1)`,
// `https://example.com/foo(bar)`) so a stray inner `)` isn't left dangling as
// literal text after the link is parsed.
const INLINE_TOKEN = /\*\*(.+?)\*\*|\[([^\]]+)\]\(((?:[^()]|\([^()]*\))*)\)/g;

/**
 * Parses `**bold**` and `[label](url)` tokens inside a single line of
 * restricted markdown into a flat token list. A `[label](url)` whose `url`
 * fails `isSafeLinkUrl` degrades to a plain `text` token holding only the
 * label — the unsafe URL is dropped entirely, never carried into the output.
 */
export function parseInline(text: string): InlineToken[] {
  const tokens: InlineToken[] = [];
  let lastIndex = 0;
  INLINE_TOKEN.lastIndex = 0;
  let match: RegExpExecArray | null = INLINE_TOKEN.exec(text);
  while (match !== null) {
    if (match.index > lastIndex) {
      tokens.push({ type: 'text', text: text.slice(lastIndex, match.index) });
    }
    const boldText = match[1];
    if (boldText !== undefined) {
      tokens.push({ type: 'bold', text: boldText });
    } else {
      const label = match[2] ?? '';
      const url = match[3] ?? '';
      if (isSafeLinkUrl(url)) {
        tokens.push({ type: 'link', label, href: url });
      } else {
        // Unsafe scheme: keep the label text, drop the link entirely.
        tokens.push({ type: 'text', text: label });
      }
    }
    lastIndex = INLINE_TOKEN.lastIndex;
    match = INLINE_TOKEN.exec(text);
  }
  if (lastIndex < text.length) {
    tokens.push({ type: 'text', text: text.slice(lastIndex) });
  }
  return tokens;
}

/**
 * Groups `body` lines into paragraph/list blocks and parses each line's
 * inline content (see `parseInline`). A line starting with `- ` or `* ` joins
 * the preceding list block (or starts a new one); anything else becomes its
 * own paragraph. Blank lines are separators only and never produce a block.
 *
 * This is the single source of truth for restricted-markdown parsing — both
 * the plugin WebView and the www admin render this same `Block[]` output
 * with their own JSX, so they can never disagree on what counts as bold,
 * a link, or a list item.
 */
export function parseRestrictedMarkdown(body: string): RestrictedMarkdownBlock[] {
  const blocks: RestrictedMarkdownBlock[] = [];
  for (const rawLine of body.split('\n')) {
    const line = rawLine.trim();
    if (!line) continue;
    const listMatch = /^[-*]\s+(.*)$/.exec(line);
    if (listMatch) {
      const last = blocks[blocks.length - 1];
      if (last && last.type === 'list') {
        last.items.push(parseInline(listMatch[1] ?? ''));
      } else {
        blocks.push({ type: 'list', items: [parseInline(listMatch[1] ?? '')] });
      }
    } else {
      blocks.push({ type: 'paragraph', tokens: parseInline(line) });
    }
  }
  return blocks;
}
